import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Bear連携: プランの自動保存 | Plannotator","description":"PlannotatorのBear連携設定方法を学びます。x-callback-urlを使用して承認したプランを自動保存し、スマートタグ生成でナレッジの蓄積とプランのアーカイブを実現します。","frontmatter":{"title":"Bear連携: プランの自動保存 | Plannotator","sidebarTitle":"プランをBearに自動保存","subtitle":"Bear連携: 承認したプランを自動保存 | Plannotator","description":"PlannotatorのBear連携設定方法を学びます。x-callback-urlを使用して承認したプランを自動保存し、スマートタグ生成でナレッジの蓄積とプランのアーカイブを実現します。","tags":["連携","Bear","ノートアプリ","ナレッジ管理"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"ja/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"ja/backnotprop/plannotator/advanced/bear-integration/index.md"}'),l={name:"ja/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(n,t,d,s,c,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="bear連携-承認したプランを自動保存" tabindex="-1">Bear連携：承認したプランを自動保存 <a class="header-anchor" href="#bear連携-承認したプランを自動保存" aria-label="Permalink to &quot;Bear連携：承認したプランを自動保存&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><p>Bear連携を有効にすると、プランを承認するたびにPlannotatorが自動的にBearノートに保存します：</p><ul><li>自動生成されるタイトル（プランから抽出）</li><li>スマートタグ（プロジェクト名、キーワード、プログラミング言語）</li><li>プランの完全な内容</li></ul><p>これにより、承認したすべてのプランを一箇所で管理でき、後から参照したりナレッジとして蓄積したりできます。</p><h2 id="今あなたが直面している課題" tabindex="-1">今あなたが直面している課題 <a class="header-anchor" href="#今あなたが直面している課題" aria-label="Permalink to &quot;今あなたが直面している課題&quot;">​</a></h2><p>こんな経験はありませんか：</p><ul><li>AIが生成したプランが良かったので、後で参照できるように保存したい</li><li>Bearに手動でコピー＆ペーストするのが面倒</li><li>異なるプロジェクトのプランが混在し、タグで整理できていない</li></ul><p>Bear連携を使えば、これらの問題を自動的に解決できます。</p><h2 id="このチュートリアルが役立つ場面" tabindex="-1">このチュートリアルが役立つ場面 <a class="header-anchor" href="#このチュートリアルが役立つ場面" aria-label="Permalink to &quot;このチュートリアルが役立つ場面&quot;">​</a></h2><ul><li>Bearをメインのノートアプリとして使用している</li><li>承認したプランをナレッジベースとしてアーカイブしたい</li><li>タグを使って過去のプランを素早く検索したい</li></ul><div class="info custom-block"><p class="custom-block-title">Bearについて</p><p>BearはmacOS向けのMarkdownノートアプリで、タグ、暗号化、同期などの機能をサポートしています。まだインストールしていない場合は、<a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a>をご覧ください。</p></div><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><ul><li>Plannotatorがインストール済み（<a href="./../../start/installation-claude-code/">インストールチュートリアル</a>を参照）</li><li>Bearがインストール済みで正常に動作している</li><li>基本的なプランレビューの流れを理解している（<a href="./../../platforms/plan-review-basics/">プランレビューの基本</a>を参照）</li></ul><h2 id="基本的な仕組み" tabindex="-1">基本的な仕組み <a class="header-anchor" href="#基本的な仕組み" aria-label="Permalink to &quot;基本的な仕組み&quot;">​</a></h2><p>Bear連携の核心は <strong>x-callback-url</strong> プロトコルです：</p><ol><li>Plannotator UIでBear連携を有効化（ブラウザのlocalStorageに保存）</li><li>プラン承認時、Plannotatorが <code>bear://x-callback-url/create</code> URLを送信</li><li>システムが <code>open</code> コマンドでBearを自動起動しノートを作成</li><li>プランの内容、タイトル、タグが自動的に入力される</li></ol><p><strong>主な特徴</strong>：</p><ul><li>vaultパスの設定不要（Obsidianのようにvaultを指定する必要がない）</li><li>スマートタグ生成（最大7個）</li><li>プラン承認時に自動保存</li></ul><div class="tip custom-block"><p class="custom-block-title">Obsidianとの違い</p><p>Bear連携はよりシンプルで、vaultパスの設定が不要です。スイッチ一つで有効化できます。一方、Obsidianは保存フォルダの指定やより多くのカスタマイズが可能です。</p></div><h2 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h2><h3 id="ステップ1-plannotatorの設定を開く" tabindex="-1">ステップ1：Plannotatorの設定を開く <a class="header-anchor" href="#ステップ1-plannotatorの設定を開く" aria-label="Permalink to &quot;ステップ1：Plannotatorの設定を開く&quot;">​</a></h3><p>AIエージェントがプランを生成しPlannotator UIを開いた後、右上の ⚙️ <strong>Settings</strong> ボタンをクリックします。</p><p><strong>期待される結果</strong>：設定パネルが表示され、複数の設定オプションが確認できます</p><h3 id="ステップ2-bear連携を有効化" tabindex="-1">ステップ2：Bear連携を有効化 <a class="header-anchor" href="#ステップ2-bear連携を有効化" aria-label="Permalink to &quot;ステップ2：Bear連携を有効化&quot;">​</a></h3><p>設定パネルで <strong>Bear Notes</strong> セクションを見つけ、スイッチをクリックします。</p><p><strong>なぜこうするのか</strong> スイッチがグレー（無効）から青（有効）に変わり、同時にブラウザのlocalStorageに保存されます。</p><p><strong>期待される結果</strong>：</p><ul><li>Bear Notesのスイッチが青色に変わる</li><li>説明文：&quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="ステップ3-プランを承認" tabindex="-1">ステップ3：プランを承認 <a class="header-anchor" href="#ステップ3-プランを承認" aria-label="Permalink to &quot;ステップ3：プランを承認&quot;">​</a></h3><p>プランレビューが完了したら、下部の <strong>Approve</strong> ボタンをクリックします。</p><p><strong>なぜこうするのか</strong> PlannotatorがBear設定を読み取り、有効になっていれば承認と同時にBearのx-callback-urlを呼び出します。</p><p><strong>期待される結果</strong>：</p><ul><li>Bearアプリが自動的に開く</li><li>新規ノート作成ウィンドウが表示される</li><li>タイトルと内容が自動入力されている</li><li>タグが自動生成されている（<code>#</code> で始まる）</li></ul><h3 id="ステップ4-保存されたノートを確認" tabindex="-1">ステップ4：保存されたノートを確認 <a class="header-anchor" href="#ステップ4-保存されたノートを確認" aria-label="Permalink to &quot;ステップ4：保存されたノートを確認&quot;">​</a></h3><p>Bearで新しく作成されたノートを確認します：</p><ul><li>タイトルが正しいか（プランのH1から取得）</li><li>内容が完全か（プラン全文を含む）</li><li>タグが適切か（プロジェクト名、キーワード、プログラミング言語）</li></ul><p><strong>期待される結果</strong>： 以下のようなノート構造が確認できます：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">プランの完全な内容...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] SettingsでBear Notesスイッチが有効になっている</li><li>[ ] プラン承認後にBearが自動的に開く</li><li>[ ] ノートのタイトルがプランのH1と一致している</li><li>[ ] ノートにプランの完全な内容が含まれている</li><li>[ ] タグに <code>#plannotator</code> とプロジェクト名が含まれている</li></ul><h2 id="よくあるトラブルと解決策" tabindex="-1">よくあるトラブルと解決策 <a class="header-anchor" href="#よくあるトラブルと解決策" aria-label="Permalink to &quot;よくあるトラブルと解決策&quot;">​</a></h2><h3 id="bearが自動的に開かない" tabindex="-1">Bearが自動的に開かない <a class="header-anchor" href="#bearが自動的に開かない" aria-label="Permalink to &quot;Bearが自動的に開かない&quot;">​</a></h3><p><strong>原因</strong>：システムの <code>open</code> コマンドが失敗している可能性があります：</p><ul><li>BearがインストールされていないかApp Storeからダウンロードされていない</li><li>BearのURLスキームが他のアプリに乗っ取られている</li></ul><p><strong>解決策</strong>：</p><ol><li>Bearが正常にインストールされていることを確認</li><li>ターミナルで手動テスト：<code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="タグが期待通りでない" tabindex="-1">タグが期待通りでない <a class="header-anchor" href="#タグが期待通りでない" aria-label="Permalink to &quot;タグが期待通りでない&quot;">​</a></h3><p><strong>原因</strong>：タグは以下のルールで自動生成されます：</p><ul><li>必須：<code>#plannotator</code></li><li>必須：プロジェクト名（gitリポジトリ名またはディレクトリ名から抽出）</li><li>オプション：H1タイトルから最大3つのキーワードを抽出（ストップワードを除外）</li><li>オプション：コードブロックからプログラミング言語タグを抽出（json/yaml/markdownを除外）</li><li>最大7個のタグ</li></ul><p><strong>解決策</strong>：</p><ul><li>タグが期待通りでない場合は、Bearで手動編集できます</li><li>プロジェクト名が正しくない場合は、gitリポジトリの設定またはディレクトリ名を確認</li></ul><h3 id="承認したが保存されない" tabindex="-1">承認したが保存されない <a class="header-anchor" href="#承認したが保存されない" aria-label="Permalink to &quot;承認したが保存されない&quot;">​</a></h3><p><strong>原因</strong>：</p><ul><li>Bear連携が有効になっていない（Settingsを確認）</li><li>ネットワークエラーまたはBearの応答タイムアウト</li><li>プランの内容が空</li></ul><p><strong>解決策</strong>：</p><ol><li>Settingsでスイッチが青色（有効状態）であることを確認</li><li>ターミナルにエラーログがないか確認（<code>[Bear] Save failed:</code>）</li><li>プランを再度承認</li></ol><h2 id="タグ生成メカニズムの詳細" tabindex="-1">タグ生成メカニズムの詳細 <a class="header-anchor" href="#タグ生成メカニズムの詳細" aria-label="Permalink to &quot;タグ生成メカニズムの詳細&quot;">​</a></h2><p>Plannotatorはスマートにタグを生成し、Bearでプランを素早く検索できるようにします。以下はタグの生成ルールです：</p><table tabindex="0"><thead><tr><th>タグの出典</th><th>例</th><th>優先度</th></tr></thead><tbody><tr><td>固定タグ</td><td><code>#plannotator</code></td><td>必須</td></tr><tr><td>プロジェクト名</td><td><code>#myproject</code>、<code>#plannotator</code></td><td>必須</td></tr><tr><td>H1キーワード</td><td><code>#authentication</code>、<code>#api</code></td><td>オプション（最大3個）</td></tr><tr><td>プログラミング言語</td><td><code>#typescript</code>、<code>#python</code></td><td>オプション</td></tr></tbody></table><p><strong>ストップワードリスト</strong>（タグにならない）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>除外されるプログラミング言語</strong>（タグにならない）：</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>例：タグ生成プロセス</summary><p>プランのタイトルが &quot;Implementation Plan: User Authentication System in TypeScript&quot; で、コードブロックにPythonとJSONが含まれている場合：</p><ol><li><strong>固定タグ</strong>：<code>#plannotator</code></li><li><strong>プロジェクト名</strong>：<code>#myproject</code>（gitリポジトリ名と仮定）</li><li><strong>H1キーワード</strong>： <ul><li><code>implementation</code> → 除外（ストップワード）</li><li><code>plan</code> → 除外（ストップワード）</li><li><code>user</code> → 保持 → <code>#user</code></li><li><code>authentication</code> → 保持 → <code>#authentication</code></li><li><code>system</code> → 保持 → <code>#system</code></li><li><code>typescript</code> → 保持 → <code>#typescript</code></li></ul></li><li><strong>プログラミング言語</strong>： <ul><li><code>python</code> → 保持 → <code>#python</code></li><li><code>json</code> → 除外（除外リスト）</li></ul></li></ol><p>最終タグ：<code>#plannotator #myproject #user #authentication #system #typescript #python</code>（7個、上限に達成）</p></details><h2 id="obsidian連携との比較" tabindex="-1">Obsidian連携との比較 <a class="header-anchor" href="#obsidian連携との比較" aria-label="Permalink to &quot;Obsidian連携との比較&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特徴</th><th>Bear連携</th><th>Obsidian連携</th></tr></thead><tbody><tr><td>設定の複雑さ</td><td>シンプル（スイッチのみ）</td><td>中程度（vaultとフォルダの選択が必要）</td></tr><tr><td>保存先</td><td>Bearアプリ内</td><td>指定したvaultパス</td></tr><tr><td>ファイル名</td><td>Bear自動管理</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>なし（Bearは非対応）</td><td>あり（created, source, tags）</td></tr><tr><td>クロスプラットフォーム</td><td>macOSのみ</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ 使用</td><td>❌ 直接ファイル書き込み</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">どちらを選ぶべきか</p><ul><li>macOSのみ使用しBearが好みなら：Bear連携がよりシンプル</li><li>クロスプラットフォームやカスタム保存パスが必要なら：Obsidian連携がより柔軟</li><li>両方使いたい場合：同時に有効化可能（プラン承認時に両方に保存）</li></ul></div><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Bear連携はx-callback-urlプロトコルで動作し、設定がシンプル</li><li>Settingsでスイッチをオンにするだけで、パス指定は不要</li><li>プラン承認時に自動的にBearに保存</li><li>スマートタグ生成：プロジェクト名、キーワード、プログラミング言語を含む（最大7個）</li><li>Obsidian連携と比較して、Bearはよりシンプルだが機能は少なめ</li></ul><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../remote-mode/">リモート/Devcontainerモード</a></strong> を学びます。</p><p>学べること：</p><ul><li>リモート環境（SSH、Devcontainer、WSL）でPlannotatorを使用する方法</li><li>固定ポートとポートフォワーディングの設定</li><li>リモート環境でブラウザを開いてレビュー画面を表示する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Bear設定インターフェース</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Bearへの保存</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>タグ抽出</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>タイトル抽出</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Bear設定インターフェース</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Bear設定の読み取り</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Bear設定の保存</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI設定コンポーネント</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>承認時のBear呼び出し</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>サーバーでのBear処理</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>主要な関数</strong>：</p><ul><li><code>saveToBear(config: BearConfig)</code>：x-callback-urlを使用してプランをBearに保存</li><li><code>extractTags(markdown: string)</code>：プラン内容からスマートにタグを抽出（最大7個）</li><li><code>extractTitle(markdown: string)</code>：プランのH1タイトルからノートタイトルを抽出</li><li><code>getBearSettings()</code>：localStorageからBear連携設定を読み取り</li><li><code>saveBearSettings(settings)</code>：Bear連携設定をlocalStorageに保存</li></ul><p><strong>主要な定数</strong>：</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>：localStorageでのBear設定のキー名</li></ul><p><strong>Bear URLフォーマット</strong>：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
